import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Login: React.FC<{ setUser: (u: any) => void }> = ({ setUser }) => {
  const [name, setName] = useState('');
  const [isSwahili, setIsSwahili] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name) return;

    try {
      const res = await fetch('http://localhost:5001/api/users', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name }),
      });
      const data = await res.json();
      localStorage.setItem('tf_user', JSON.stringify(data));
      setUser(data);
      navigate('/onboarding');
    } catch (err) {
      console.error('Failed to login', err);
    }
  };

  return (
    <div className="container text-center">
      <div style={{ marginTop: '100px' }}>
        <h1 style={{ color: 'var(--primary)', fontSize: '3rem', marginBottom: '10px' }}>Twende Fom</h1>
        <p style={{ marginBottom: '30px', color: '#666' }}>
          {isSwahili ? 'Panga na ufurahie na marafiki' : 'Plan and enjoy with friends'}
        </p>

        <button 
          onClick={() => setIsSwahili(!isSwahili)} 
          style={{ marginBottom: '20px', background: 'none', border: '1px solid var(--gray)', color: '#333' }}
        >
          {isSwahili ? 'English' : 'Swahili'}
        </button>

        <form onSubmit={handleLogin} className="card">
          <div className="input-group">
            <label>{isSwahili ? 'Jina lako' : 'Your Name'}</label>
            <input 
              type="text" 
              value={name} 
              onChange={(e) => setName(e.target.value)} 
              placeholder={isSwahili ? 'Ingiza jina' : 'Enter your name'}
              required
            />
          </div>
          <button type="submit" className="primary" style={{ width: '100%' }}>
            {isSwahili ? 'Anza Sasa' : 'Get Started'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default Login;
